defmodule ProductWeb.ProductController do
  use ProductWeb, :controller

  def index(conn, params) do
    search = String.replace(params[:search], " ", "%")
    query = from(p in Product, where: fragment("name LIKE ?", "%#{search}%"))

    case Repo.chronological(query) do
      {results, _extra_info} ->
        renderconn(conn, "index.json", results)
      error ->
        renderconn(conn, "error.json", %{error: error})
    end
  end
end